template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; n > i; i++) {
      if (out[i] != ref_out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scan_with_bank_conflicts_kernel(const T* in, T* out, int64_t num_blocks)
{
  __shared__ T temp[N];

  int thid = threadIdx.x;
  for (int64_t bid = (int64_t)blockIdx.x; bid < num_blocks; bid += (int64_t)gridDim.x) {
    const T* t_in = in + bid * N;
    T* t_out = out + bid * N;

    int offset = 1;

    temp[2 * thid]     = t_in[2 * thid];
    temp[2 * thid + 1] = t_in[2 * thid + 1];

    for (int d = N >> 1; d > 0; d >>= 1) {
      __syncthreads();
      if (d > thid) {
        int ai = offset * (2 * thid + 1) - 1;
        int bi = offset * (2 * thid + 2) - 1;
        temp[bi] += temp[ai];
      }
      offset <<= 1;
    }

    if (thid == 0) temp[N - 1] = 0;

    for (int d = 1; d < N; d <<= 1) {
      offset >>= 1;
      __syncthreads();
      if (d > thid) {
        int ai = offset * (2 * thid + 1) - 1;
        int bi = offset * (2 * thid + 2) - 1;
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }

    __syncthreads();
    t_out[2 * thid]     = temp[2 * thid];
    t_out[2 * thid + 1] = temp[2 * thid + 1];
    __syncthreads();
  }
}

template<typename T, int N>
__global__ void scan_without_bank_conflicts_kernel(const T* in, T* out, int64_t num_blocks)
{
  __shared__ T temp[2 * N];

  int thid = threadIdx.x;
  for (int64_t bid = (int64_t)blockIdx.x; bid < num_blocks; bid += (int64_t)gridDim.x) {
    const T* t_in = in + bid * N;
    T* t_out = out + bid * N;

    int a = thid;
    int b = a + (N / 2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);

    temp[a + oa] = t_in[a];
    temp[b + ob] = t_in[b];

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1) {
      __syncthreads();
      if (d > thid) {
        int ai = offset * (2 * thid + 1) - 1;
        int bi = offset * (2 * thid + 2) - 1;
        ai = ai + OFFSET(ai);
        bi = bi + OFFSET(bi);
        temp[bi] += temp[ai];
      }
      offset <<= 1;
    }

    if (thid == 0) temp[N - 1 + OFFSET(N - 1)] = 0;

    for (int d = 1; d < N; d <<= 1) {
      offset >>= 1;
      __syncthreads();
      if (d > thid) {
        int ai = offset * (2 * thid + 1) - 1;
        int bi = offset * (2 * thid + 2) - 1;
        ai = ai + OFFSET(ai);
        bi = bi + OFFSET(bi);
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }

    __syncthreads();
    t_out[a] = temp[a + oa];
    t_out[b] = temp[b + ob];
    __syncthreads();
  }
}

template<typename T, int N>
void runTest(const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N;
  int64_t bytes = nelems * (int64_t)sizeof(T);

  T* in = (T*)malloc((size_t)bytes);
  T* out = (T*)malloc((size_t)bytes);
  T* ref_out = (T*)malloc((size_t)bytes);

  srand(123);
  for (int64_t i = 0; nelems > i; i++) in[i] = (T)(rand() % 5 + 1);

  T* t_in = in;
  T* t_out = ref_out;
  for (int64_t blk = 0; num_blocks > blk; blk++) {
    t_out[0] = 0;
    for (int i = 1; N > i; i++) t_out[i] = t_out[i - 1] + t_in[i - 1];
    t_out += N;
    t_in += N;
  }

  T *d_in = nullptr, *d_out = nullptr;
  if (nelems > 0) {
    cudaMalloc((void**)&d_in, (size_t)bytes);
    cudaMalloc((void**)&d_out, (size_t)bytes);
    cudaMemcpy(d_in, in, (size_t)bytes, cudaMemcpyHostToDevice);
  }

  int threads = N / 2;
  int grid = 0;
  if (num_blocks > 0) {
    grid = (num_blocks > 2147483647LL) ? 2147483647 : (int)num_blocks;
  }

  auto start = std::chrono::steady_clock::now();
  for (int i = 0; repeat > i; i++) {
    if (num_blocks > 0) {
      scan_with_bank_conflicts_kernel<T, N><<<grid, threads>>>(d_in, d_out, num_blocks);
    }
  }
  cudaDeviceSynchronize();
  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }

  if (nelems > 0) cudaMemcpy(out, d_out, (size_t)bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out, out, nelems);

  start = std::chrono::steady_clock::now();
  for (int i = 0; repeat > i; i++) {
    if (num_blocks > 0) {
      scan_without_bank_conflicts_kernel<T, N><<<grid, threads>>>(d_in, d_out, num_blocks);
    }
  }
  cudaDeviceSynchronize();
  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  if (nelems > 0) cudaMemcpy(out, d_out, (size_t)bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out, out, nelems);

  if (d_in) cudaFree(d_in);
  if (d_out) cudaFree(d_out);
  free(in);
  free(out);
  free(ref_out);
}

template<int N>
void run(const int n, const int repeat)
{
  for (int i = 0; 2 > i; i++) {
    bool report_timing = 0 < i;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest<char,  N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<int,   N>(n, repeat, report_timing);
    runTest<long,  N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (3 != argc) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }

  const int n = atoi(argv[1]);
  const int data_0 = atoi(argv[2]);

  run< 128>(n, data_0);
  run< 256>(n, data_0);
  run< 512>(n, data_0);
  run<1024>(n, data_0);
  run<2048>(n, data_0);

  return 0;
}
